// components/CustomTooltip.jsx
import { createPortal } from 'react-dom';

function CustomTooltip({ 
  position, visible, children, onClose, 
  title, footerVisible, navVisible 
}) {
  if (!visible) return null;

  return createPortal(
    <div 
      id="myCustomTooltip"
      className="custom-tooltip"
      style={{
        position: 'fixed',
        left: position.x + 'px',
        top: position.y + 10 + 'px',
        display: 'block',
        zIndex: 9999
      }}
      onClick={(e) => e.stopPropagation()}
    >
      {title && <div id="tooltipTitle">{title}</div>}
      <div id="tooltipContent">{children}</div>
      {navVisible && <div id="monthNav">{/* навигация месяцев */}</div>}
      {footerVisible && <div id="tooltipFooter">{/* кнопки */}</div>}
    </div>,
    document.body
  );
}
